import React, { useEffect, useMemo, useState } from "react";
import "./App.css";

const fallbackImages = [
  "https://images.unsplash.com/photo-1600891964599-f61ba0e24092?auto=format&fit=crop&w=1200&q=80",
  "https://images.unsplash.com/photo-1546069901-ba9599a7e63c?auto=format&fit=crop&w=1200&q=80",
  "https://images.unsplash.com/photo-1565299624946-b28f40a0ae38?auto=format&fit=crop&w=1200&q=80",
  "https://images.unsplash.com/photo-1504674900247-0877df9cc836?auto=format&fit=crop&w=1200&q=80"
];

function App() {
  const [foods, setFoods] = useState([]);
  const [search, setSearch] = useState("");
  const [category, setCategory] = useState("All");
  const [cart, setCart] = useState([]);
  const [bgIndex, setBgIndex] = useState(0);

  useEffect(() => {
    fetch("http://localhost:8080/foods")
      .then((res) => res.json())
      .then((data) => setFoods(Array.isArray(data) ? data : []))
      .catch((err) => console.log(err));
  }, []);

  useEffect(() => {
    const timer = setInterval(() => {
      setBgIndex((prev) => (prev + 1) % fallbackImages.length);
    }, 3500);

    return () => clearInterval(timer);
  }, []);

  const categories = useMemo(() => {
    return ["All", ...new Set(foods.map((food) => food.category))];
  }, [foods]);

  const filteredFoods = useMemo(() => {
    return foods.filter((food) => {
      const categoryMatch = category === "All" || food.category === category;
      const searchMatch = food.name.toLowerCase().includes(search.toLowerCase());
      return categoryMatch && searchMatch;
    });
  }, [foods, category, search]);

  const popularFoods = useMemo(() => {
    return foods.slice(0, 6);
  }, [foods]);

  const addToCart = (food) => {
    const existing = cart.find((item) => item.id === food.id);

    if (existing) {
      setCart(
        cart.map((item) =>
          item.id === food.id
            ? { ...item, quantity: item.quantity + 1 }
            : item
        )
      );
    } else {
      setCart([...cart, { ...food, quantity: 1 }]);
    }
  };

  const total = cart.reduce((sum, item) => sum + item.price * item.quantity, 0);

  return (
    <div className="app-shell">
      <div
        className="background-slider"
        style={{ backgroundImage: `url("${fallbackImages[bgIndex]}")` }}
      />

      <header className="hero-section">
        <div className="hero-overlay">
          <p className="hero-tag">Campus Dining Experience</p>
          <h1>College Canteen Restaurant</h1>
          <p className="hero-subtitle">
            Fresh meals, fast ordering, beautiful menu experience.
          </p>
        </div>
      </header>

      <section className="toolbar">
        <div className="search-box">
          <span>🔍</span>
          <input
            type="text"
            placeholder="Search dishes..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        <div className="category-row">
          {categories.map((cat) => (
            <button
              key={cat}
              className={category === cat ? "category-btn active" : "category-btn"}
              onClick={() => setCategory(cat)}
            >
              {cat}
            </button>
          ))}
        </div>
      </section>

      <section className="section-block">
        <div className="section-head">
          <h2>🔥 Popular Picks</h2>
          <p>Top favorites from the canteen today</p>
        </div>

        <div className="popular-grid">
          {popularFoods.map((food, index) => (
            <div className="popular-card" key={food.id || index}>
              <img
                src={food.imageUrl || fallbackImages[index % fallbackImages.length]}
                alt={food.name}
              />
              <div className="popular-card-content">
                <h3>{food.name}</h3>
                <p>{food.category}</p>
                <span>₹{food.price}</span>
              </div>
            </div>
          ))}
        </div>
      </section>

      <section className="main-layout">
        <div className="menu-panel">
          <div className="section-head">
            <h2>🍽 Full Menu</h2>
            <p>Restaurant style cards with food images and animations</p>
          </div>

          <div className="menu-grid">
            {filteredFoods.map((food, index) => (
              <div className="menu-card" key={food.id || index}>
                <div className="image-wrap">
                  <img
                    src={food.imageUrl || fallbackImages[index % fallbackImages.length]}
                    alt={food.name}
                    className="food-image"
                  />
                  <span className="badge">{food.category}</span>
                </div>

                <div className="menu-card-body">
                  <h3>{food.name}</h3>
                  <div className="rating-row">
                    <span className="stars">★★★★★</span>
                    <span className="rating-text">4.6</span>
                  </div>
                  <div className="price-row">
                    <span className="price">₹{food.price}</span>
                    <button className="add-btn" onClick={() => addToCart(food)}>
                      Add
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <aside className="cart-panel">
          <div className="cart-card">
            <h2>🛒 Cart</h2>

            {cart.length === 0 ? (
              <p className="empty-text">No items added yet</p>
            ) : (
              cart.map((item) => (
                <div key={item.id} className="cart-item">
                  <div>
                    <strong>{item.name}</strong>
                    <p>
                      {item.quantity} × ₹{item.price}
                    </p>
                  </div>
                  <span>₹{item.quantity * item.price}</span>
                </div>
              ))
            )}

            <div className="cart-total">
              <span>Total</span>
              <strong>₹{total}</strong>
            </div>

            <button className="checkout-btn">Proceed to Checkout</button>
          </div>
        </aside>
      </section>
    </div>
  );
}

export default App;
